#include<bits/stdc++.h>
using namespace std;

bool prime_number(long long x) { //判断质数
	if (x <= 1) return false;
	for (int i = 2; i * i <= x; i++) if (x % i == 0) return false;
	return true;
}
int main() {
	int n, m, ans = 0;
	cin >> n >> m;
	if(n>m) swap(n,m);
	for (int i = n; i <= m; i++) if (prime_number(i)) ans++;
	cout << ans;
	return 0;
}
